import React from 'react';
import clsx from 'clsx';
import { useTreeContext } from './hooks/TreeContext';
import { useTreeNodeContext } from './hooks/TreeNodeContext';
import { isFunction } from '../util';

export const TreeNodeContainer = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<'div'>>(
  ({ className, onClick, ...restProps }, ref) => {
    const { rootCssScope, selectedCache, selectable, toggleSelected, checkable, toggleChecked } = useTreeContext();
    const { doublyTreeNode: node, checkboxRef, expandButtonRef } = useTreeNodeContext();
    const { value, disabled = false } = node.__node__;
    const isSelected = selectedCache.get(value);

    return (
      <div
        ref={ref}
        className={clsx(
          rootCssScope('__node'),
          isSelected && rootCssScope('__node-selected'),
          disabled && rootCssScope('__node-disabled'),
          className,
        )}
        onClick={e => {
          isFunction(onClick) && onClick(e);
          if (e.isDefaultPrevented()) {
            return;
          }
          const { target } = e;
          if (
            (target instanceof HTMLElement || target instanceof SVGElement) &&
            ((checkboxRef.current && checkboxRef.current.contains(target)) ||
              (expandButtonRef.current && expandButtonRef.current.contains(target)))
          ) {
            return;
          }
          if (selectable) {
            toggleSelected(value);
          } else if (checkable) {
            // 如果 !selectable 并且是 checkable 则选中
            toggleChecked(value);
          }
        }}
        {...restProps}
      />
    );
  },
);
